206→// extractCoreOrJSONB returns the CSV cell value for a descriptor.
207→// Core fields (name, city, state, unit_id) are extracted from scanned columns;
208→// all others are extracted from the data JSONB blob via OutputKey.
209→func extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
210→	switch d.Name {
211→	case "name":
212→		return instName
213→	case "city":
214→		return city
215→	case "state":
216→		return state
217→	case "unit_id":
218→		return unitID
219→	default:
220→		if d.OutputKey == "" {
221→			return ""
222→		}
223→		raw := extractJSONBValue(data, d.OutputKey)
224→		if raw != "" && len(d.Options) > 0 {
225→			return d.LabelForCode(raw)
226→		}
227→		return raw
228→	}
229→}
230→
231→// extractJSONBValue navigates a dot-separated path into a JSON blob and
232→// returns the value as a string. Returns "" for nil, missing, or unparseable.
233→func extractJSONBValue(data json.RawMessage, dotPath string) string {
234→	if len(data) == 0 {
235→		return ""
236→	}
237→	parts := strings.Split(dotPath, ".")
238→	var current any
239→	if err := json.Unmarshal(data, &current); err != nil {
240→		return ""
241→	}
242→	for _, part := range parts {
243→		m, ok := current.(map[string]any)
244→		if !ok {
245→			return ""
246→		}
247→		current, ok = m[part]
248→		if !ok {
249→			return ""
250→		}
251→	}
252→	if current == nil {
253→		return ""
254→	}
255→	return fmt.Sprintf("%v", current)
256→}
257→
258→// writeJSONError writes a JSON error response with the given status code and message.
259→func writeJSONError(w http.ResponseWriter, status int, message string) {
260→	w.Header().Set("Content-Type", "application/json")
261→	w.WriteHeader(status)
262→	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
263→}
