 1→package auth
 2→
 3→import "context"
 4→
 5→type contextKey struct{}
 6→
 7→// SetClaims stores JWT claims in the context.
 8→func SetClaims(ctx context.Context, claims *Claims) context.Context {
 9→	return context.WithValue(ctx, contextKey{}, claims)
10→}
11→
12→// GetClaims retrieves JWT claims from the context. Returns nil if not present.
13→func GetClaims(ctx context.Context) *Claims {
14→	claims, _ := ctx.Value(contextKey{}).(*Claims)
15→	return claims
16→}
17→
18→// MustGetClaims retrieves JWT claims from the context.
19→// Panics if claims are not present — only call this in handlers behind auth middleware.
20→func MustGetClaims(ctx context.Context) *Claims {
21→	claims := GetClaims(ctx)
22→	if claims == nil {
23→		panic("auth: claims not found in context — handler must be behind auth middleware")
24→	}
25→	return claims
26→}
